const items = $input.all();

if (!items || items.length === 0 || !items[0].json) {
  throw new Error('No input items found for member_agreement_id');
}

const row = items[0].json;

if (!row.member_agreement_id) {
  throw new Error('member_agreement_id is missing from the row data');
}
if (!row.documenso_template_envelope_id) {
  throw new Error('Missing agreement_templates.documenso_template_envelope_id. Run db/migrations_documenso_integration.sql and seed the template row.');
}
if (!row.documenso_member_recipient_id || !row.documenso_facilitator_recipient_id) {
  throw new Error('Missing agreement_templates Documenso recipient IDs (member/facilitator).');
}

const memberEmail = (row.member_email || '').trim();
const facilitatorEmail = (row.facilitator_email || '').trim();
const emailRe = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

if (!emailRe.test(memberEmail)) {
  throw new Error(`Invalid/missing member_email: "${memberEmail}"`);
}
if (!emailRe.test(facilitatorEmail)) {
  throw new Error(`Invalid/missing facilitator_email: "${facilitatorEmail}"`);
}

const externalId = $('Webhook').first().json.body.externalId || `ma:${row.member_agreement_id}`;

// Prefer the member_email_id selected by Appsmith on member_agreements. If it is not set,
// the SQL query resolves the current primary active email, then verified/newest as fallback.

return [{
  json: {
    member_agreement_id: row.member_agreement_id,
    member_id: row.member_id,
    facilitator_id: row.facilitator_id,
    member_email_id: row.resolved_member_email_id || row.member_email_id || null,
    facilitator_email_id: row.resolved_facilitator_email_id || null,
    member_email: memberEmail,
    facilitator_email: facilitatorEmail,
    externalId,
    payload: {
      envelopeId: row.documenso_template_envelope_id,
      distributeDocument: true,
      externalId,
      recipients: [
        {
          id: row.documenso_member_recipient_id,
          email: memberEmail,
          name: `${row.member_first_name ?? ''} ${row.member_last_name ?? ''}`.trim()
        },
        {
          id: row.documenso_facilitator_recipient_id,
          email: facilitatorEmail,
          name: `${row.facilitator_first_name ?? ''} ${row.facilitator_last_name ?? ''}`.trim()
        }
      ]
    }
  }
}];

const full = $json;
const body = full.body ?? full;

const documensoId = body.id;
if (!documensoId) {
  throw new Error(`Documenso /envelope/use response missing id. Response: ${JSON.stringify(full)}`);
}

const recipients = body.recipients || [];
const memberSigner = recipients.find(r => r.signingOrder === 1) || recipients[0];
const facilitatorSigner = recipients.find(r => r.signingOrder === 2) || recipients[1];
const built = $('Build Documenso Payload').first().json;

return [{
  json: {
    documenso_document_id: documensoId,
    member_agreement_id: built.member_agreement_id,
    externalId: built.externalId,
    member_email_id: built.member_email_id || null,
    member_email: built.member_email,
    facilitator_email: built.facilitator_email,
    member_signing_url: memberSigner?.signingUrl,
    facilitator_signing_url: facilitatorSigner?.signingUrl,
    recipients
  }
}];
